// LAYER 1+2: Extract & Validate (§4.1 PRE-validate)
// Zero-throw: returns Standard Contract error, never throws

const raw = $input.first().json;
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

function ve(code, msg) {
  return [{ json: {
    success: false, error_code: code, error_message: msg, data: null,
    _meta: { source: 'DB_Get_Providers', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _exit_early: true
  }}];
}

// === ACTIVE FILTER VALIDATION (optional) ===
let active = null;
if (input.active !== undefined && input.active !== null) {
  if (typeof input.active === 'boolean') {
    active = input.active;
  } else if (typeof input.active === 'string') {
    const activeStr = input.active.toLowerCase().trim();
    if (activeStr === 'true' || activeStr === '1') {
      active = true;
    } else if (activeStr === 'false' || activeStr === '0') {
      active = false;
    } else {
      return ve('INVALID_TYPE', 'active must be a boolean (true/false)');
    }
  } else {
    return ve('INVALID_TYPE', 'active must be a boolean (true/false)');
  }
}

return [{ json: {
  success: true,
  active,
  _validated: true
}}];

// Gate: only pass valid items to Build Query
const input = $input.first().json;
if (input._exit_early) return [];
return [{ json: input }];

// Gate: only pass validation errors to skip query
const input = $input.first().json;
if (!input._exit_early) return [];
return [{ json: input }];

// Build query to get all providers
// Note: Using only columns that exist in providers table
const { active } = $input.first().json;
let providers_query;
if (active === null || active === undefined) {
  providers_query = `SELECT id, name, email, active, created_at FROM providers ORDER BY name;`;
} else if (active === true) {
  providers_query = `SELECT id, name, email, active, created_at FROM providers WHERE active = true ORDER BY name;`;
} else {
  providers_query = `SELECT id, name, email, active, created_at FROM providers WHERE active = false ORDER BY name;`;
}

return [{ json: {
  ...$input.first().json,
  providers_query,
  active
}}];

// Handle DB error during providers query
const e = $input.first().json;
const upstreamData = $('Build Providers Query').isExecuted ? $('Build Providers Query').first().json : {};
let error_code = 'DB_QUERY_ERROR';
let error_message = e.message || e.error?.message || 'Database query error';

if (error_message.includes('connection') || error_message.includes('ECONNREFUSED')) {
  error_code = 'DB_CONNECTION_ERROR';
  error_message = 'Database connection failed';
} else if (error_message.includes('timeout')) {
  error_code = 'DB_TIMEOUT';
  error_message = 'Database query timeout';
} else if (error_message.includes('relation') && error_message.includes('does not exist')) {
  error_code = 'TABLE_NOT_FOUND';
  error_message = 'Providers table does not exist';
}

return [{ json: {
  ...upstreamData,
  success: false, error_code, error_message, data: null,
  _meta: { source: 'DB_Get_Providers', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// Format providers response
const items = $input.all();
const upstreamData = $('Build Providers Query').isExecuted ? $('Build Providers Query').first().json : {};

let providers = [];
// Postgres alwaysOutputData=true returns [{json: {}}] when 0 rows
if (items.length > 0 && Object.keys(items[0].json).length > 0) {
  providers = items.map(item => ({
    id: item.json.id,
    name: item.json.name,
    email: item.json.email,
    active: item.json.active,
    created_at: item.json.created_at
  }));
}

return [{ json: {
  success: true,
  error_code: null,
  error_message: null,
  data: {
    providers,
    total: providers.length,
    active_filter: upstreamData.active !== undefined ? upstreamData.active : null
  },
  _meta: {
    source: 'DB_Get_Providers',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id
  }
}}];

// UNIFIED OUTPUT — Standard Contract (§3.2)
const items = $input.all();
let finalItem = items.find(i => i.json.data !== undefined || i.json.error_code !== undefined);
if (!finalItem) finalItem = items.find(i => i.json._exit_early);
if (!finalItem) { 
  return [{ json: { success: false, error_code: 'PIPELINE_ERROR', error_message: 'No valid output found', data: null, _meta: { source: 'DB_Get_Providers', timestamp: new Date().toISOString(), workflow_id: $workflow.id } } }]; 
}
const input = finalItem.json;
return [{ json: {
  success: input.success === true,
  error_code: input.error_code || null,
  error_message: input.error_message || null,
  data: input.data || null,
  _meta: input._meta || {
    source: 'DB_Get_Providers',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id
  }
}}];
